import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define fused kernel for LogSumExp + HardSwish + bias subtraction + clamp + max reduction
fused_ops_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <math.h>

template<typename T>
__device__ __forceinline__ T sigmoid_approx(T x) {
    return 1.0f / (1.0f + __expf(-x));
}

__global__ void fused_ops_kernel(
    const float* __restrict__ input, 
    const float* __restrict__ bias, 
    float* __restrict__ output,
    int batch_size,
    int channels,
    int depth,
    int height,
    int width,
    int spatial_size
) {
    // Each thread handles one spatial position across all channels
    int spatial_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (spatial_idx >= spatial_size) return;

    int batch_idx = blockIdx.y;
    int total_spatial = depth * height * width;

    // Calculate base indices
    int base_input_idx = (batch_idx * channels) * spatial_size + spatial_idx;
    int base_output_idx = batch_idx * spatial_size + spatial_idx;

    // Shared memory for reduction
    extern __shared__ float shared_mem[];
    float* channel_vals = shared_mem;

    // Load all channel values for this spatial position
    for (int c = threadIdx.y; c < channels; c += blockDim.y) {
        if (spatial_idx < spatial_size) {
            int input_idx = base_input_idx + c * spatial_size;
            channel_vals[c] = input[input_idx];
        }
    }
    __syncthreads();

    // Thread 0 of each warp performs LogSumExp reduction
    if (threadIdx.y == 0) {
        // Find max value
        float max_val = -INFINITY;
        for (int c = 0; c < channels; c++) {
            if (channel_vals[c] > max_val) {
                max_val = channel_vals[c];
            }
        }

        // Sum exponentials
        float sum_exp = 0.0f;
        for (int c = 0; c < channels; c++) {
            sum_exp += __expf(channel_vals[c] - max_val);
        }

        float logsumexp_result = __logf(sum_exp) + max_val;

        // HardSwish: x * sigmoid(x + 3) / 6
        float swish_input = logsumexp_result + 3.0f;
        float sigmoid_val = sigmoid_approx(swish_input);
        float hardswish_result = logsumexp_result * sigmoid_val / 6.0f;

        // Subtract bias (using first channel's bias since we're reducing across channels)
        float biased_result = hardswish_result - bias[0];

        // Clamp between -1 and 1
        float clamped_result = fminf(fmaxf(biased_result, -1.0f), 1.0f);

        // Find max across channels for final output
        float max_final = -INFINITY;
        for (int c = 0; c < channels; c++) {
            // Apply same operations to each channel for max reduction
            float channel_val = channel_vals[c];
            float swish_channel = channel_val + 3.0f;
            float sigmoid_channel = sigmoid_approx(swish_channel);
            float hardswish_channel = channel_val * sigmoid_channel / 6.0f;
            float biased_channel = hardswish_channel - bias[c];
            float clamped_channel = fminf(fmaxf(biased_channel, -1.0f), 1.0f);

            if (clamped_channel > max_final) {
                max_final = clamped_channel;
            }
        }

        output[base_output_idx] = max_final;
    }
}

torch::Tensor fused_ops_cuda(torch::Tensor input, torch::Tensor bias) {
    auto sizes = input.sizes();
    int batch_size = sizes[0];
    int channels = sizes[1];
    int depth = sizes[2];
    int height = sizes[3];
    int width = sizes[4];
    int spatial_size = depth * height * width;

    // Output tensor: [batch_size, 1, depth, height, width]
    auto output = torch::empty({batch_size, 1, depth, height, width}, 
                               torch::device(torch::kCUDA).dtype(torch::kFloat32));

    // Optimized thread block configuration
    dim3 block_size(256, 1);  // x: spatial, y: channels
    dim3 grid_size((spatial_size + block_size.x - 1) / block_size.x, batch_size);

    // Calculate shared memory size
    int shared_mem_size = channels * sizeof(float);

    fused_ops_kernel<<<grid_size, block_size, shared_mem_size>>>(
        input.data_ptr<float>(),
        bias.data_ptr<float>(),
        output.data_ptr<float>(),
        batch_size,
        channels,
        depth,
        height,
        width,
        spatial_size
    );

    return output;
}
"""

fused_ops_cpp_source = "torch::Tensor fused_ops_cuda(torch::Tensor input, torch::Tensor bias);"

# Compile the fused CUDA kernel
fused_ops = load_inline(
    name="fused_ops",
    cpp_sources=fused_ops_cpp_source,
    cuda_sources=fused_ops_source,
    functions=["fused_ops_cuda"],
    verbose=False,
    extra_cflags=["-O3", "-ffast-math"],
    extra_ldflags=[""],
)

class ModelNew(nn.Module):
    """
    Optimized model with fully fused CUDA kernel for all operations after conv transpose.
    """
    def __init__(self, in_channels, out_channels, kernel_size, stride, padding, bias_shape):
        super(ModelNew, self).__init__()
        self.conv_transpose = nn.ConvTranspose3d(in_channels, out_channels, kernel_size, stride=stride, padding=padding)
        self.bias = nn.Parameter(torch.randn(bias_shape))
        self.fused_ops = fused_ops

    def forward(self, x):
        x = self.conv_transpose(x)
        x = self.fused_ops.fused_ops_cuda(x, self.bias)
        return x

