    int total_spatial = depth * height * width;

    // Calculate base indices
    int base_input_idx = (batch_idx * channels) * spatial_size + spatial_idx;
    int base_output_idx = batch_idx * spatial_size + spatial_idx;

    // Shared memory for reduction
    extern __shared__ float shared_mem[];
    float* channel_vals = shared_mem;

    // Load all channel values for this spatial position
    for (int c = threadIdx.y; c < channels; c += blockDim.y) {
